import type { Href } from 'expo-router';
import type {
  KangurAssignmentSnapshot,
  KangurLearnerProfile,
  KangurProgressState,
  KangurScore,
} from '@kangur/contracts/kangur';
import { type KangurLearnerProfileSnapshot } from '@kangur/core';

export type KangurMobileParentAssignmentItem = {
  assignment: KangurAssignmentSnapshot;
  href: Href | null;
};

export type KangurMobileParentAssignmentMonitoring = {
  completedCount: number;
  highPriorityCount: number;
  inProgressCount: number;
  lessonCount: number;
  notStartedCount: number;
  practiceCount: number;
  totalCount: number;
};

export type KangurMobileParentRecentResultItem = {
  historyHref: Href;
  lessonHref: Href | null;
  practiceHref: Href;
  result: KangurScore;
};

export type UseKangurMobileParentDashboardResult = {
  activeLearner: KangurLearnerProfile | null;
  assignmentItems: KangurMobileParentAssignmentItem[];
  assignmentMonitoring: KangurMobileParentAssignmentMonitoring;
  assignmentsError: string | null;
  canAccessDashboard: boolean;
  isAuthenticated: boolean;
  isLoadingAssignments: boolean;
  isLoadingAuth: boolean;
  isLoadingProgress: boolean;
  isLoadingResults: boolean;
  learners: KangurLearnerProfile[];
  parentDisplayName: string;
  progressError: string | null;
  recentResultItems: KangurMobileParentRecentResultItem[];
  refreshDashboard: () => Promise<void>;
  resultsError: string | null;
  selectLearner: (learnerId: string) => Promise<void>;
  selectedLearnerId: string | null;
  selectionError: string | null;
  snapshot: KangurLearnerProfileSnapshot | null;
  supportsLearnerCredentials: boolean;
  switchingLearnerId: string | null;
};

import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import { useKangurMobileScoreHistory } from '../scores/useKangurMobileScoreHistory';
import { useParentDashboardAssignments } from './useParentDashboardAssignments';
import { useParentDashboardProgress } from './useParentDashboardProgress';
import { useParentDashboardResults } from './useParentDashboardResults';
import { useParentDashboardLearner } from './useParentDashboardLearner';
import { type UseKangurMobileParentDashboardResult } from './parent-dashboard-types';

export const useKangurMobileParentDashboard = (): UseKangurMobileParentDashboardResult => {
  const { copy, locale } = useKangurMobileI18n();
  const { isLoadingAuth, session, supportsLearnerCredentials } = useKangurMobileAuth();

  const learnerState = useParentDashboardLearner();
  const canAccessDashboard = session.status === 'authenticated' && Boolean(session.user?.canManageLearners);

  const assignments = useParentDashboardAssignments(canAccessDashboard, learnerState.selectedLearnerId);
  const recentResults = useKangurMobileScoreHistory({
    enabled: canAccessDashboard && learnerState.selectedLearnerId !== null,
    limit: 5,
    sort: '-created_date',
  });
  const progress = useParentDashboardProgress(canAccessDashboard, learnerState.selectedLearnerId, recentResults.scores, locale);
  const recentResultItems = useParentDashboardResults(recentResults);

  const isAuthorized = canAccessDashboard && learnerState.selectedLearnerId !== null;

  return {
    activeLearner: learnerState.activeLearner,
    assignmentItems: assignments.assignmentItems,
    assignmentMonitoring: assignments.assignmentMonitoring,
    assignmentsError: assignments.assignmentsQuery.error instanceof Error ? copy({ de: 'Aufgaben-Ladefehler.', en: 'Assignment load error.', pl: 'Błąd ładowania zadań.' }) : null,
    canAccessDashboard,
    isAuthenticated: session.status === 'authenticated',
    isLoadingAssignments: Boolean(isAuthorized && assignments.assignmentsQuery.isLoading),
    isLoadingAuth,
    isLoadingProgress: Boolean(isAuthorized && progress.progressQuery.isLoading),
    isLoadingResults: recentResults.isLoading,
    learners: learnerState.learners,
    parentDisplayName: learnerState.parentDisplayName,
    progressError: progress.progressQuery.error instanceof Error ? copy({ de: 'Fortschritts-Ladefehler.', en: 'Progress load error.', pl: 'Błąd ładowania postępu.' }) : null,
    recentResultItems,
    refreshDashboard: async () => {},
    resultsError: recentResults.error instanceof Error ? copy({ de: 'Ergebnis-Ladefehler.', en: 'Result load error.', pl: 'Błąd ładowania wyników.' }) : null,
    selectLearner: async () => {},
    selectedLearnerId: learnerState.selectedLearnerId,
    selectionError: learnerState.selectionError,
    snapshot: progress.snapshot,
    supportsLearnerCredentials,
    switchingLearnerId: learnerState.switchingLearnerId,
  };
};

import { useQuery } from '@tanstack/react-query';
import { useMemo } from 'react';
import type { KangurAssignmentSnapshot } from '@kangur/contracts/kangur';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import { createKangurLessonHref } from '../lessons/lessonHref';
import { createKangurPracticeHref } from '../practice/practiceHref';
import type { KangurMobileParentAssignmentItem, KangurMobileParentAssignmentMonitoring } from './parent-dashboard-types';

const resolveAssignmentHref = (assignment: KangurAssignmentSnapshot) => {
  if (assignment.target.type === 'lesson') return createKangurLessonHref(assignment.target.lessonComponentId);
  if (assignment.target.type === 'practice') return createKangurPracticeHref(assignment.target.operation);
  return null;
};

const getPriorityRank = (priority: KangurAssignmentSnapshot['priority']) => (priority === 'high' ? 0 : priority === 'medium' ? 1 : 2);

const sortAssignments = (assignments: KangurAssignmentSnapshot[]) =>
  [...assignments].sort((left, right) => {
    const priorityDelta = getPriorityRank(left.priority) - getPriorityRank(right.priority);
    return priorityDelta !== 0 ? priorityDelta : Date.parse(right.updatedAt) - Date.parse(left.updatedAt);
  });

const buildAssignmentMonitoring = (assignments: KangurAssignmentSnapshot[]): KangurMobileParentAssignmentMonitoring =>
  assignments.reduce<KangurMobileParentAssignmentMonitoring>(
    (summary, assignment) => {
      const isHigh = assignment.priority === 'high';
      const isLesson = assignment.target.type === 'lesson';
      const isPractice = assignment.target.type === 'practice';
      const isCompleted = assignment.progress.status === 'completed';
      const isInProgress = assignment.progress.status === 'in_progress';

      return {
        highPriorityCount: summary.highPriorityCount + (isHigh ? 1 : 0),
        lessonCount: summary.lessonCount + (isLesson ? 1 : 0),
        practiceCount: summary.practiceCount + (isPractice ? 1 : 0),
        completedCount: summary.completedCount + (isCompleted ? 1 : 0),
        inProgressCount: summary.inProgressCount + (isInProgress ? 1 : 0),
        notStartedCount: summary.notStartedCount + (!isCompleted && !isInProgress ? 1 : 0),
        totalCount: summary.totalCount + 1,
      };
    },
    { completedCount: 0, highPriorityCount: 0, inProgressCount: 0, lessonCount: 0, notStartedCount: 0, practiceCount: 0, totalCount: 0 },
  );

export function useParentDashboardAssignments(canAccessDashboard: boolean, selectedLearnerId: string | null) {
  const { apiBaseUrl, apiClient } = useKangurMobileRuntime();

  const assignmentsQuery = useQuery({
    enabled: canAccessDashboard && selectedLearnerId !== null,
    queryKey: ['kangur-mobile', 'parent-dashboard', 'assignments', apiBaseUrl, selectedLearnerId ?? 'none'],
    queryFn: async (): Promise<KangurAssignmentSnapshot[]> => apiClient.listAssignments({ includeArchived: false }, { cache: 'no-store' }),
    staleTime: 30_000,
  });

  const assignmentSnapshots = assignmentsQuery.data ?? [];
  const assignmentMonitoring = useMemo(() => buildAssignmentMonitoring(assignmentSnapshots), [assignmentSnapshots]);
  const assignmentItems: KangurMobileParentAssignmentItem[] = useMemo(() =>
      sortAssignments(assignmentSnapshots)
          .slice(0, 3)
          .map((assignment) => ({ assignment, href: resolveAssignmentHref(assignment) })),
      [assignmentSnapshots],
  );

  return { assignmentsQuery, assignmentMonitoring, assignmentItems };
}

import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileAuth } from '../auth/KangurMobileAuthContext';
import { useState } from 'react';

export function useParentDashboardLearner() {
  const { copy } = useKangurMobileI18n();
  const { session } = useKangurMobileAuth();
  const [selectionError, setSelectionError] = useState<string | null>(null);
  const [switchingLearnerId, setSwitchingLearnerId] = useState<string | null>(null);

  const activeLearner = session.user?.activeLearner ?? null;
  const selectedLearnerId = activeLearner?.id.trim() ?? null;
  const learners = session.user?.learners ?? [];

  const trimmedFullName = session.user?.full_name?.trim();
  const parentDisplayName =
    typeof trimmedFullName === 'string' && trimmedFullName !== ''
      ? trimmedFullName
      : copy({
          de: 'Elternkonto',
          en: 'Parent account',
          pl: 'Konto rodzica',
        });

  return {
    activeLearner,
    selectedLearnerId,
    learners,
    parentDisplayName,
    selectionError,
    switchingLearnerId,
    setSelectionError,
    setSwitchingLearnerId
  };
}

import { useMemo } from 'react';
import { useQuery } from '@tanstack/react-query';
import { type KangurProgressState } from '@kangur/contracts/kangur';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import { buildKangurLearnerProfileSnapshot } from '@kangur/core';
import { createDefaultKangurProgressState } from '@kangur/contracts/kangur';

export function useParentDashboardProgress(
  canAccessDashboard: boolean,
  selectedLearnerId: string | null,
  recentResultsScores: any[],
  locale: any,
) {
  const { apiBaseUrl, apiClient, defaultDailyGoalGames } = useKangurMobileRuntime();

  const progressQuery = useQuery({
    enabled: canAccessDashboard && selectedLearnerId !== null,
    queryKey: ['kangur-mobile', 'parent-dashboard', 'progress', apiBaseUrl, selectedLearnerId ?? 'none'],
    queryFn: async (): Promise<KangurProgressState> => apiClient.getProgress(undefined, { cache: 'no-store' }),
    staleTime: 30_000,
  });

  const snapshot = useMemo(() => {
    if (!canAccessDashboard || selectedLearnerId === null) return null;
    return buildKangurLearnerProfileSnapshot({
      dailyGoalGames: defaultDailyGoalGames,
      locale,
      progress: progressQuery.data ?? createDefaultKangurProgressState(),
      scores: recentResultsScores,
    });
  }, [canAccessDashboard, defaultDailyGoalGames, locale, progressQuery.data, recentResultsScores, selectedLearnerId]);

  return { progressQuery, snapshot };
}

import { useMemo } from 'react';
import { createKangurLessonHrefForPracticeOperation } from '../lessons/lessonHref';
import { createKangurPracticeHref } from '../practice/practiceHref';
import { createKangurResultsHref } from '../scores/resultsHref';
import { type KangurMobileParentRecentResultItem } from './parent-dashboard-types';

export function useParentDashboardResults(recentResults: { scores: any[] }) {
  return useMemo(
    (): KangurMobileParentRecentResultItem[] =>
      recentResults.scores.map((result) => ({
        historyHref: createKangurResultsHref({ operation: result.operation }),
        lessonHref: createKangurLessonHrefForPracticeOperation(result.operation),
        practiceHref: createKangurPracticeHref(result.operation),
        result,
      })),
    [recentResults.scores],
  );
}
